            "version": "33"
        },
        "MemFree": 2278547456,
        "MemTotal": 31541956608,
        "OCIRuntime": "crun",
        "SwapFree": 4227592192,
        "SwapTotal": 4294963200,
        "arch": "amd64",
        "cpus": 8,
        "hostname": "localhost.localdomain",
        "kernel": "5.10.22-200.fc33.x86_64",
        "os": "linux",
        "rootless": true,
        "uptime": "237h 8m 16.98s (Approximately 9.88 days)"
    },
    "store": {
        "ContainerStore": {
            "number": 38
        },
        "GraphDriverName": "overlay",
        "GraphOptions": [
            "overlay.mount_program=/usr/bin/fuse-overlayfs"
        ],
        "GraphRoot": "/home/brancz/.local/share/containers/storage",
        "GraphStatus": {
